INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "やばいですね☆なの！", 1, 1, "ペコリーヌのプリン", "プリンセスなプリンなの\nお店にあったいろんな食べもの\nを入れられるだけ入れてみたの\nどんな味なのか楽しみなの", "おいしすぎて食べ始めたら\n止まらない最高のプリンなの\n今のミヤコを止められるヤツは\n誰もいないの", 100, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "主さま、なの！", 2, 1, "コッコロのプリン", "いつもオマエのそばに寄りそう\nヤツのぷりんなの。ミヤコの\nワガママもやさしく受け入れて\nくれそうなの", "なんだかすごくやさしい気持ち\nになる味なの…\nおはようからおやすみまで\nずっと一緒な味なの…", 101, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "ぶっ殺すぞ！なの！\n…デレデレはどこなの？", 3, 0, "キャルのプリン", "ツンツンデレデレなヤツの\nプリンなの。砂糖とスパイスを\n混ぜてみたの。どんな味になる\nか楽しみなの", "いろんな味が一度で楽しめる\nプリンなの。ツンデレはプリン\nにするとおいしいの。ミヤコも\nツンデレを目指してみるの", 102, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "おにーたん♪なの！", 4, 1, "シェフィのプリン", "オマエと同じで、一度赤ちゃん\nみたいになったヤツのプリン\nなの。ヒンヤリ、プリンアイス\nにしてみたの", "あったかいところで食べる\nプリンアイスは最高なの～♪\n安心しすぎて昔の記憶のない\nミヤコも心が子どもになるの～", 103, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "ハーハッハッハ！\n世界征服なのじゃなのー！", 5, 1, "イリヤのプリン", "イリヤを見てたら思いついた\nトマトジュースが隠し味の\nプリンなの。栄養満点なの", "トマトで栄養補給も完璧なの\nどんどん力がみなぎってきて\n復活も夢じゃないの\nミヤコが復活したら…", 104, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "お兄ちゃんのエッチ！　なの！", 6, 1, "アカリのプリン", "アカリのプリンなの。ヨリと\n同じくらいかわいく作って\nやったの。正直ミヤコは\nおいしければなんでもいいの", "見た目がかわいくてもミヤコは\n味にも厳しいの。あむっ…\nこ、これは…！なんだかすごく\n変な気分になってきたの…", 105, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "えっと…その…あんたのこと…\nだ、大っ嫌いなのーー！", 7, 1, "ヨリのプリン", "かわいくつくらないとアカリが\n怒りそうだからヨリのプリンは\nかわいく作ったの。自信作なの", "んむぅ…これはなかなか感想が\n難しいプリンなの…率直に言い\nたいような…心のうちに秘めて\nおきたいような…", 106, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "お父さん…\nいいかげんにしてなの！\nん？プリンの未来は…\n見えなかったの…", 8, 0, "シノブのプリン", "シノブはいつもミヤコに\nやさしくしてくれるから\n丁寧に作ったの。ドクロ親父は\nいらないから作ってないの", "このプリンを食べるとシノブが\nミヤコの中にいるみたいなの！\nシノブの力があれば未来の\nプリンを見放題なの！", 107, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "インフェルノシールド！なの！", 9, 1, "ジュンのプリン", "黒い鎧を脱がないヤツのプリン\nなの。固めのプリンを目指したら\nカチカチになりすぎたの", "固すぎてかじれないから丸吞み\nにしたの。なんだか体が硬く\nなった気がするの。みんなを\n守れる気がするの！", 108, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "あなたといると調子が狂うな\n…なの\n翻弄してたのはオマエなの？", 10, 1, "トモのプリン", "オマエをいっつもからかってる\nヤツのプリンなの\nちょっぴり変わったスパイスで\nからかいを表現したの", "口の中でスパイスがプチプチ\nはじけて新食感なの！\nプチプチがミヤコを\n翻弄するの！", 109, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "タイガーヒーローボンバー！\nなの！", 11, 1, "マツリのプリン", "王宮騎士団にいるちっこいヤツ\nなの。ちっこいけどやるヤツ\nらしいから、濃いめの味付けに\nしてみたの", "ん～見かけによらず濃厚な\nパンチのある味わいが\n口いっぱいに広がるの！", 110, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "ま、いいんじゃん？\nしらんけどなの", 13, 1, "クロエのプリン", "なんかすごくクールなプリンなの\nなんかテンションも少し\n低そうなの。これ\n食べちゃっても大丈夫なの？", "クールな見た目なのにとっても\n優しい味なの！なんだか\n懐かしさを感じるの…", 111, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "ぷりーん★なの！", 14, 1, "チエルのプリン", "きれいにデコれたの！\nカラフルでおいしそうなの\nこれは期待できそうなの", "なんか変わった食感なの…\nちゃる…ちょる…ちぇる？\nちぇるってしてるの\nでもちぇるってなんなの？", 112, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "端的に換言すれば\n青春の味なの？", 15, 1, "ユニのプリン", "見た目は完ぺきなの！\nこれをつくったやつは\nきっと天才なの！\n早く食べたいの！", "味はなんか妙に\n甘酸っぱいの…\n食べたことない味なの\nこの味ってもしかして…", 113, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "幼なじみはあんた…なの？", 16, 1, "サレンのプリン", "オマエから聞いた懐かしい\n味ってヤツを全部入れてみたの\nオマエ記憶がないのに懐かしい\nってどういうことなの？", "ミヤコも幽霊になる前の記憶\nがないのに、なんだか懐かしい\n気持ちになってくるの…", 114, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "ひゃああんなの～！", 17, 1, "スズメのプリン", "たまたま会ったメイドに教えて\nもらった作り方なの。メイドは\nプリンも作れるはずなの。\nなのにこの不安は何なの…？", "おかしいの。このプリンを\n食べてから、３回も転んだの\nミヤコは幽霊だから転んだり\nしないの。なんでなの…？", 115, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "サルキデバレヤ！なの！", 18, 0, "クルミのプリン", "怖がりな子どもが教えてくれた\n小さくてかわいいプリンなの　\n触ってないのにぷるぷる震える\n驚きのやわらかさなの", "甘さのなかに少しのしょっぱさ\nクセになる味なの\nこのプリンはがんばればきっと\nいろんな美味しいになれるの", 116, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "プリンフルスイングなの～！", 19, 1, "アヤネのプリン", "くまのぬいぐるみを見ていたら\nひらめいたの。小さいけど\nしっかりした甘さの元気に\nなれるプリンなの！", "このプリン、食べるとなんだか\nお姉ちゃんになった気分に\nなるの。ピンチのプリンは\nミヤコが守ってやるの！", 117, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "みらくるみやりん\nくるりんぱ～☆なの！", 20, 1, "マホのプリン", "マホマホ王国って国にいる\nお姫様のプリンなの\n魔物も虜にしちゃう\nすてきなプリンなの", "メルヘンパワーがあふれてきて\nいまならミヤコにも魔法が\n使える気がするの！\nほな、いきまひょ～なの！", 118, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "ウルフェンバイトなの！", 21, 1, "マコトのプリン", "カッコいいプリンを目指して\nワイルドなものをガンガン\n入れてみたの。きっと熱い\nプリンができるはずなの", "うおーん！ミヤコなんだか\n強くなった気がするの！\n困ったことがあればミヤコが\nまとめて面倒見てやるの！", 119, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "なんくるないさ～！なの！", 22, 1, "カオリのプリン", "どっかの国でよくとれる\nゴーヤーに似てるやつを\nいれてみたの！ちょっと\n苦いらしいけど…", "一口食べたら元気が\nあふれて止まらないの！\n気分がいいから、一曲\n踊りでも披露してやるの！", 120, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "ふふん。簡単な推理なの", 23, 1, "カスミのプリン", "勘の鋭いやつが好きな食べ物を\nたくさん入れてみたの\n難しいこと考えるのにぴったり\nらしいけど、なんでなの？", "むむむ…なるほどなの\n上質な糖分をふんだんに\n使うことで、脳をより活性化\nできるからなの！", 121, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "エリザベス～！なの～！", 24, 1, "マヒルのプリン", "搾りたての牛乳を\nたっぷり使ったプリンなの～\nマヒルに手伝ってもらって\nミヤコ直々に搾ってきたの！", "ミルクがとっても濃厚で\nほっぺたが落ちちゃうの～♪\nこのプリンからは牧場の…\n自然の息吹を感じるの！", 122, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "私の好きな本…読んで\nもらえたらうれしいです…\nなの", 25, 1, "シオリのプリン", "マヒルからやさしいヤツだって\n聞いたの。やさしさを表現\nするために奥ゆかしい甘さに\n仕上げてみたの", "ほのかな甘さでありながら\nしっかりとした主張も\n感じさせる\n味わい深いプリンなの", 123, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "もふもふにしてあげるなの！", 26, 1, "リマのプリン", "牧場にいるヤツらしいの\n牛とは違うらしいの\nもふもふ気持ちいいらしいから\n食感にこだわって作ったの", "こ、これは…！口の中に入れた\n瞬間にふんわり溶けて\nなくなっちゃうの！\nその食感がやみつきなの！", 124, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "めんどくさいな～なの…", 27, 0, "リンのプリン", "いっつも寝てるやつらしいの\nぐっすり眠れる薬草をたくさん\n入れてみたの。プリンとして\nおいしくなるかはわからないの", "んむぅ…評価が難しい味なの…\nおいしいのはおいしいの…\nん～考えてたら…\n眠くなってきたの…", 125, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "プリンの権能を解放するの～！", 28, 1, "ラビリスタのプリン", "クレープ屋の真っ赤な人に\n教わったプリンなの\n作り方を丁寧に教えてくれて\nとっても優しい人だったの！", "プ…プリンなのにクレープの味\nがするの。味もすごく普通なの\nでも…なんだかプリンの新しい\n扉を開けそうな気がするの…！", 126, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "お姉ちゃんパワー全開！なの！", 29, 0, "シズルのプリン", "お店に落ちてた謎のレシピの\nプリンなの。レシピの表紙には\n『お姉ちゃんの愛情たっぷり』\nって書いてあったの", "とろける食感が絶品なの～♪\n食べるとなんだか幸せな\n気持ちになれるの…これが\n愛情ってやつなの？", 127, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "お兄ちゃん、プリンをよこすの！", 30, 1, "リノのプリン", "リノから作り方を教わったの！\nさすがクレープ屋で働いてる\nだけあって美味しそうなの！", "これで妹力？があがるらしいの。\n妹になればお兄ちゃんに\nプリンをたかり放題なの！\n最高なの～！", 128, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "困った時はお互いさまさま！\nなの！", 31, 1, "ヒヨリのプリン", "プリンのレシピで悩んでたら\n通りすがりのおねーさんが\n一緒に考えてくれたプリンなの\nいいヤツもたまにはいるの～♪", "食べたら元気が湧いてくるの\nだからプリンのレシピのお礼に\nミヤコも人助けを手伝って\nやったの。ミヤコはえらいの！", 129, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "フラワリングヒールなの～♪", 32, 1, "ユイのプリン", "ミヤコががんばって作った\nこだわりのプリンなの～\nプリンは癒しなの。だから優しい\n気持ちで丁寧に作ったの", "はっ…思わずお花畑が見えたの\n身も心も包まれるような\nとっても優しい味がするの\nこれは…まさに癒しなの～♪", 130, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "スラッシュテンペスト！なの。", 33, 1, "レイのプリン", "究極のプリンを作るため\nミヤコは厳しい修行をしたの…\nその結果あって完成した\nクールで完璧なプリンなの！", "確かに完璧なプリンなの\nでも究極のプリンと呼ぶには\nまだまだ修行が必要なの…\nプリン作りは奥が深いの…！", 131, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "おーほっほほほ！なの！", 34, 1, "アキノのプリン", "豪華で高級な\nお嬢様プリンなの\n中には宝石みたいな\n大きいイチゴを入れるの！", "味にも素材にもこだわりが\nあるの。一流は妥協しないの\nもっと豪華に、もっとおいしく\nできるはず…", 132, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "プリしゅわ最高～！なの！", 35, 1, "ユカリのプリン", "外はしっかり、中はふわとろの\nプリンにするの\n泡みたいなしゅわしゅわの\n生クリームも入れるの♪", "プリンは飲み物とも言うの\nぐいっていってみるの\n…ふわしゅわでとろけるの～！\n体に染みわたるの～", 133, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "にゃにゃにゃ！なの！", 36, 1, "タマキのプリン", "餡子を入れて\nオーブンでこんがり焼くの\nたい…焼きプリンなの\n斬新なの！", "このプリンは焼きたてのうちに\n食べるのが一番なの…！\n熱いけどおいしくて\nうずうずしてきたの…！", 134, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "効率全開！なの！", 37, 0, "ミフユのプリン", "栄養バランスを考えて\n木の実をたくさん入れるの\nあれこれ忙しいときでも\n頼りになるプリンなの！", "プリンはいつでも手軽に\n食べられるのも魅力なの\nこれは食べ応えもあるから一つ\n食べればいっぱい動けるの", 135, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "あらあら～なの～♪", 38, 1, "ミサトのプリン", "エルフの森で子どもにもらった\n薬草を使って作ったの\nこんな優しい味のプリンは\n初めてなの…", "このプリンを食べてから\nいい子になった気がするの\n大好きなプリンを泣いてる子に\nあげたの。いい気分なの", 136, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "スヤスヤ～…なの…", 39, 1, "ハツネのプリン", "お昼寝でみた夢の中に\nでてきた不思議なプリンを\n作ってみたの。見てたらまた\n眠くなってきたの…", "あまいプリンが口の中で\nぽんぽん弾ける未知の味なの！\n今なら不思議な力で世界も\n救えそうなの！でも眠くなるの…", 137, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "ぼっちは卒業なの～！", 40, 1, "アオイのプリン", "お店のはしっこに一つだけ\n残ったおもちゃを見て思い\nついたの。他のプリンと一緒に\n置いておくと震えだすの", "知らないうちにはしっこに\n隠れちゃってたの。食べたら\nミヤコ、シノブたちに会いに\nいきたくなってきたの", 138, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "リズムあげるのー！", 41, 1, "ノゾミのプリン", "トップオブアイドルの\nプリンなの。キラキラした\nものを入れて、あつ～い\nオーブンで焼いてみたの", "口の中に華やかな甘さが\n広がる…これがアイドルなの？\n急に歌って踊りたく\nなってきたの！", 139, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "風の加護を！なの！", 42, 1, "チカのプリン", "ミヤコにプリンをくれるすごく\nいいヤツのプリンなの\n精霊に呼びかけながら\n一生懸命かき混ぜたの", "プリンの生地がとっても\nなめらかで最高の舌触りなの！\n精霊、ミヤコのプリンのために…", 140, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "騎士さんのために\nしたんじゃありません！なの！", 43, 1, "ツムギのプリン", "歌って踊って衣装も作れるヤツ\nのプリンなの。このプリンは\nきれいに包装するの。プリンを\n最高の形で着飾らせるの", "包装は食べるまでの手間が\n増えてめんどくさいの。でも\nそのめんどくささもプリンの\n味を引き立てるの", 141, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "宴の始まりなの！", 12, 0, "クリスティーナのプリン", "プリンをくれないならどうでも\nいいヤツなの。でも横で\nいろいろ言ってきたから\nがんばって作ったの", "んむっ！？\nく、口のなかでプリンの\nおいしさが大暴れなの！\n止まらないの！", 142, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "一刀両断、覚悟しな！なの！", 44, 1, "ルカのプリン", "大人な甘さ控えめのプリンを\n作るの。試しにお魚を入れて\nみるの。プリンの可能性は\n無限大なの！", "大人の味なの。今やミヤコは\nみんなの頼れる姐御なの！\n悪さするやつはミヤコが\n許さないの！", 143, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "きゅぴーん！キタコレ！なの！", 45, 1, "ナナカのプリン", "サイカワサイツヨな\n魔法のプリンなの\n中身をカラフルにするの～\n甘いプリンは頭が冴えるの！", "一口食べる度に味が変わって\n魔法みたいなの！\nもしかして全部食べたら\nミヤコも魔法少女になれるの？", 144, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "人呼んで、疾風のミヤコなの！", 46, 1, "アンナのプリン", "小難しい言葉をささやきながら\n作ったら魔力あふれるプリンが\n爆誕したの！でも、不思議と\nイタイタしいのはなぜなの～？", "一口食べたら謎の組織に\n狙われたり、前世の記憶が蘇る\n気がするの～設定盛りすぎなの\nミヤコは、ミヤコは…", 145, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "クスクス…クスクスクス…なの", 47, 1, "エリコのプリン", "甘酸っぱい赤い木の実を\n切り刻んで入れるの\n甘くてちょっぴり刺激的な\nヤンデレのプリンなの", "なんか普通のプリンよりも\nいい匂いがするの～…\nプリンのことがもっともっと\n好きになっちゃうの…", 146, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "どんなプリンも\nミヤコの隻眼からは\n逃れられないの～！", 48, 1, "ミツキのプリン", "健康に気を遣うミヤコは\nプリンにお薬を入れてみたの～\nでもなんだか毒々しいから\n彩りにバラを添えてみたの～", "鼻に抜ける薬のにおいがアレ\nだけど大人っぽくて頭が\nよくなった気がするの。無性に\n実験したくてしかたないの", 147, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "私は子どもではない！なの！", 49, 1, "モニカのプリン", "小さいけどしっかりした\n軍人のプリンなの\nちょっと固めにして\n砂糖はいっぱい入れるの", "ん～王道なプリンは\n甘くて安定したおいしさなの～\n思わず笑顔になっちゃうの\nにこにこなの～♪…はっ！", 148, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "ショーグン！　ミヤコと一緒に\n天下統一するデースなの！", 50, 1, "ニノンのプリン", "オーエド町で手に入れた素材と\nトーゴクに伝わる術をかけて\nプリンを作るの。シュババ！\n忍法隠し味の術なの！", "このプリンを食べてから\n誰かにお仕えしなきゃ\nいけない気がするデースなの\nそれはショ、ショー…", 149, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "…ぐふふ、じゅるり～なの", 51, 0, "クウカのプリン", "オマエが持ってきた手錠を\nヒントに作ったプリンなの\nプリンが動けないように\nカチカチに固めたの", "カチカチに固めたせいで食感が\nプリンのようで\nプリンじゃないの…でもこの\nもどかしさが癖になるの…", 150, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "あぁ、ミヤコはなんて美しいの～", 52, 1, "ユキのプリン", "とっても美しいプリンなの\n美しいものを手当たり次第\n入れたらすごいことになったの", "味も美しい以外の感想が\n出てこないの。ていうかこれを\n食べたミヤコも美しいの！\n鏡、鏡はどこなの！", 151, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "ジー…ってミヤコなにしてるの\nミヤコはストーカーじゃないの！", 53, 0, "アユミのプリン", "知らないうちにお菓子が売れた\n時に思いついたプリンなの。\n作り方もよく覚えてない…\nけど、きっとおいしいの！", "うん、やっぱりおいしく…\nん？あそこにいるのは\nアイツなの。あれ？\n体が勝手にアイツの方に…", 152, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "にひひ…イタズラの時間なの！", 54, 0, "ミソギのプリン", "イタズラ好きの手下と一緒に\n作ったプリンなの。見た目は\nかわいいけど、作り方は\n意外と複雑なの～", "見た目通り甘々で優しい味なの\nでも、レシピを見たら裏面に\n別の作り方が書いてあるの。\nこれだと激辛プリンに…", 153, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "ぴょんぴょこぴょーん、なの♪", 55, 0, "ミミのプリン", "素直でやさしい手下と一緒に\n動物のぬいぐるみをいっぱい\n並べて作ったの", "ん～、ふわふわの甘々なの！\nなんだか楽しくなって\n心も体もるんたったしてくるの", 154, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "へんたいふしんしゃさんなの！", 56, 0, "キョウカのプリン", "幽霊を怖がっている手下と\n一緒に作ったプリンなの。\n小さいクセにきっちりしてて\nとってもかわいいプリンなの", "ひんやりしてて暑い日でも\nおいしく食べられそうなの！\nん？これを買いたい大人が\nいる？それって…", 155, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "ハート狙い撃ち！なの！", 57, 1, "スズナのプリン", "カリスマモデルなプリンなの\nモリモリにデコレーションして\nカリスマ感を演出したの", "見て食べて楽しめる新機軸の\nプリンなの。ミヤコは幽霊\nだけど自分の足でランウェイを\n歩きたくなってきたの！", 156, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "授業を始めます♪なの！", 58, 0, "イオのプリン", "学校の先生をしてるヤツの\nプリンなの。お堅くしようと\nしたら、いつの間にか色っぽく\nなっちゃったの。なんでなの？", "プ、プリンは全部ミヤコのもの\nなのに、なんだかこのプリンは\nいろんな人に教えたく\nなっちゃう不思議な味なの！", 157, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "立派なレディ、なの！", 59, 1, "ミサキのプリン", "少し背伸びしたおませな子を\n表現したプリンなの。あえて\n甘さ控えめなの。カラメルは\n後乗せできるから安心するの", "ミヤコはプリンならどんなもの\nでも食べるの。でもカラメルを\nちょっとだけ足すの。\nちょっとだけなら…", 158, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "プリンを持ってこないと\nお仕置きだよ～☆なの！", 60, 1, "ホマレのプリン", "謎に包まれたプリンができたの\n何か隠してるようなの…\nこれは危険なプリンなの！", "味はすごいゴージャスなの！\nボスの風格があるの！\nビッグなミヤコに\nプリンを捧げるの！", 159, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "たぎってきたの！", 61, 1, "カヤのプリン", "ワイルドな見た目なの！\nこれは期待できそうなの。\nきっと躍動感あふれる味なの！", "最初の一口目が\nすごいインパクトなの！\n無性にケンカしたくなるの！\nプリンをよこせなの！", 160, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "下剋上、やってやるですなの！", 62, 0, "イノリのプリン", "なんか見た目がパッとしないの\nこれほんとに大丈夫なの？\nなんか頼りないの…", "見た目はアレだけど味はおいし\nいの…あと主張もはっきりして\nるの！やる気と自信だけは\n出てきたのうおおおーなの！", 161, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "どけどけ～！なの～！", 63, 1, "ムイミのプリン", "天下の大悪党のプリンなの\nこれまでのジョーシキに\n捉われないプリンを\n作ってみたの～", "むむむ…食べたら\nやる気が湧いてきたの！\nミヤコを邪魔するやつはみんな\nまとめてぶっ飛ばしてやるの～", 162, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "ミラーミラー！なの！", 64, 1, "ネネカのプリン", "いろんなものに変身したり\n分身したりできるヤツの\nプリンなの。型で同じプリンを\nたくさんたくさん作ったの", "いつのまにか作ったの全部\n食べちゃったの。なんで\nプリンは分身しないの？\n無限に増えろなの！", 163, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "プリンに忠誠を誓いますわ！\nなの！", 65, 1, "クレジッタのプリン", "金の亡者のプリンなの\n金にものを言わせて作って\nみたの。おばあちゃんの\nプリンと対極なの", "むぅ…認めたくないけど\nおいしいの…これを何個も\n作れるほどのお金を稼ぐのは\n大変なの…でもおいしいから…", 164, 5);
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (3, "ギルド管理協会へようこそ！\nなの！", 66, 1, "カリンのプリン", "みんなお世話になるギルド\n管理協会職員のプリンなの\nお役所感を出すために手堅く\n王道に作ったの", "手堅い…！手堅いの…！\n隙のないプリンなの！\n今のミヤコなら完璧な\n書類作成ができそうなの！", 165, 5);
